class t{static wgs84ToTencent(t,n){if(!this.isInChina(n,t))return{lat:t,lng:n};let a=this.transformLat(n-105,t-35),e=this.transformLng(n-105,t-35),s=t/180*this.pi,i=Math.sin(s);i=1-this.ee*i*i;let r=Math.sqrt(i);a=180*a/(this.a*(1-this.ee)/(i*r)*this.pi),e=180*e/(this.a/r*Math.cos(s)*this.pi);const h=n+e;return{lat:Number((t+a).toFixed(6)),lng:Number(h.toFixed(6))}}static tencentToWgs84(t,n){if(!this.isInChina(n,t))return{lat:t,lng:n};let a=t,e=n;for(let s=0;s<5;s++){const s=this.wgs84ToTencent(a,e),i=t-s.lat,r=n-s.lng;if(a+=i,e+=r,Math.abs(i)<1e-7&&Math.abs(r)<1e-7)break}return{lat:Number(a.toFixed(6)),lng:Number(e.toFixed(6))}}static batchConvertCoordinates(t,n="tencent"){return Array.isArray(t)?t.map(((t=null)=>{if(!t)return t;const a=Number(t.latitude),e=Number(t.longitude);if(isNaN(a)||isNaN(e))return console.warn("设备经纬度无效",t),t;let s=null;return s="tencent"===n?this.wgs84ToTencent(a,e):this.tencentToWgs84(a,e),new UTSJSONObject(Object.assign(Object.assign({},t),{latitude:s.lat,longitude:s.lng,originalLatitude:a,originalLongitude:e}))})):[]}static convertCoordinate(t,n,a="wgs84",e="tencent"){return"wgs84"===a&&"tencent"===e?this.wgs84ToTencent(t,n):"tencent"===a&&"wgs84"===e?this.tencentToWgs84(t,n):(console.warn("不支持的坐标系转换",a,"->",e),{lat:t,lng:n})}static isInChina(t,n){return t>=72.004&&t<=137.8347&&n>=.8293&&n<=55.8271}static transformLat(t,n){let a=2*t-100+3*n+.2*n*n+.1*t*n+.2*Math.sqrt(Math.abs(t));return a+=2*(20*Math.sin(6*t*Math.PI)+20*Math.sin(2*t*Math.PI))/3,a+=2*(20*Math.sin(n*Math.PI)+40*Math.sin(n/3*Math.PI))/3,a+=2*(160*Math.sin(n/12*Math.PI)+320*Math.sin(n*Math.PI/30))/3,a}static transformLng(t,n){let a=300+t+2*n+.1*t*t+.1*t*n+.1*Math.sqrt(Math.abs(t));return a+=2*(20*Math.sin(6*t*Math.PI)+20*Math.sin(2*t*Math.PI))/3,a+=2*(20*Math.sin(t*Math.PI)+40*Math.sin(t/3*Math.PI))/3,a+=2*(150*Math.sin(t/12*Math.PI)+300*Math.sin(t/30*Math.PI))/3,a}}t.a=6378245,t.ee=.006693421622965943,t.pi=3.141592653589793;export{t as C};
